import {
  AppDefinition,
  AppDefinitionListItem,
  AppReview,
  AppSubmissionReview,
  AppVersion,
  InstallationContext,
  AppStats,
  VersionContext,
  IntegrationPoint,
  FeeModel,
  AppInvite,
} from '../app-store.models';
import {
  AppDefinitionListItemApiResponse,
  AppReviewApiResponse,
  AppSubmissionReviewApiResponse,
  AppVersionApiResponse,
  InstallationContextApiResponse,
  VersionContextApiResponse,
  AppInviteApiResponse,
} from './app-store-api.models';
import { AppDefinitionResponse } from '../../api/model/appDefinitionResponse';
import { FeeModel as FeeModelApi } from '../../api/model/feeModel';
import { AppStats as AppStatsApi } from '../../api/model/appStats';
import { VersionContext as VersionContextApi } from '../../api/model/versionContext';
import { IntegrationPoint as IntegrationPointApi } from '../../api/model/integrationPoint';
import { isDefined } from '../../../../shared/utils';

/**
 * Maps IntegrationPoint API response to frontend model
 */
/**
 * Maps a generated integration point, or returns null when the backend omits
 * screenId — an integration point without a target screen is unusable, so we
 * drop it rather than fabricate an invalid screenId.
 */
function mapIntegrationPointFromApi(
  apiPoint: IntegrationPointApi,
): IntegrationPoint | null {
  if (!isDefined(apiPoint.screenId)) {
    return null;
  }
  return {
    screenId: apiPoint.screenId,
    requiredPermissions: apiPoint.requiredPermissions ?? [],
    baseUrl: apiPoint.baseUrl ?? '',
  };
}

function mapFeeModelFromApi(api: FeeModelApi): FeeModel {
  return { type: api.type ?? 'perInstallation', amount: api.amount ?? 0 };
}

function mapAppStatsFromGeneratedApi(api: AppStatsApi | undefined): AppStats {
  return {
    averageRating: api?.averageRating ?? 0,
    reviewCount: api?.reviewCount ?? 0,
    installCount: api?.installCount ?? 0,
  };
}

function mapInstallationContextFromApi(
  api: InstallationContextApiResponse,
): InstallationContext {
  return {
    id: api.id,
    isEnabled: api.isEnabled,
    configuration: api.configuration,
    pendingFeeAcknowledgement: api.pendingFeeAcknowledgement,
    estimatedCost: api.estimatedCost,
    grantedPermissions: api.grantedPermissions ?? {},
  };
}

function mapVersionContextFromApi(
  api: VersionContextApiResponse,
): VersionContext {
  return {
    activeVersionId: api.activeVersionId,
    activeVersionNumber: api.activeVersionNumber,
    pendingVersionId: api.pendingVersionId,
    pendingVersionNumber: api.pendingVersionNumber,
    pendingVersionStatus: api.pendingVersionStatus,
    active: api.active ? mapAppVersionFromApi(api.active) : undefined,
    pending: api.pending ? mapAppVersionFromApi(api.pending) : undefined,
  };
}

function mapVersionContextFromGeneratedApi(
  api: VersionContextApi | undefined,
): VersionContext {
  return {
    activeVersionId: api?.activeVersionId,
    activeVersionNumber: api?.activeVersionNumber,
    pendingVersionId: api?.pendingVersionId,
    pendingVersionNumber: api?.pendingVersionNumber,
    pendingVersionStatus: api?.pendingVersionStatus ?? undefined,
  };
}

/**
 * Maps AppDefinition API response to frontend model
 */
export function mapAppDefinitionFromApi(
  apiResponse: AppDefinitionResponse,
): AppDefinition {
  return {
    id: apiResponse.id ?? '',
    developerId: apiResponse.developerId ?? '',
    developerName: apiResponse.developerName ?? '',
    name: apiResponse.name ?? '',
    description: apiResponse.description ?? '',
    shortDescription: apiResponse.shortDescription ?? '',
    iconUrl: apiResponse.iconUrl ?? '',
    state: apiResponse.state ?? 'inactive',
    visibility: apiResponse.visibility ?? 'unlisted',
    feeModel: isDefined(apiResponse.feeModel)
      ? mapFeeModelFromApi(apiResponse.feeModel)
      : null,
    version: mapVersionContextFromGeneratedApi(apiResponse.version),
    integrationPoints: (apiResponse.integrationPoints ?? [])
      .map(mapIntegrationPointFromApi)
      .filter(isDefined),
    healthCheckUrl: apiResponse.healthCheckUrl,
    categories: apiResponse.categories ?? [],
    tags: apiResponse.tags ?? [],
    stats: mapAppStatsFromGeneratedApi(apiResponse.stats),
    installation: undefined,
    updatedDate: apiResponse.updatedDate ?? '',
    createdDate: apiResponse.createdDate ?? '',
  };
}

/**
 * Maps AppDefinitionListItem API response to frontend model
 */
export function mapAppDefinitionListItemFromApi(
  apiResponse: AppDefinitionListItemApiResponse,
): AppDefinitionListItem {
  return {
    id: apiResponse.id,
    developerId: apiResponse.developerId,
    developerName: apiResponse.developerName,
    name: apiResponse.name,
    description: apiResponse.description,
    shortDescription: apiResponse.shortDescription,
    iconUrl: apiResponse.iconUrl,
    state: apiResponse.state,
    visibility: apiResponse.visibility,
    feeModel: apiResponse.feeModel ? mapFeeModelFromApi(apiResponse.feeModel) : null,
    version: mapVersionContextFromApi(apiResponse.version),
    // The list endpoint can omit these array/object fields even though the
    // hand-written type marks them required — guard like mapAppDefinitionFromApi.
    integrationPoints: (apiResponse.integrationPoints ?? [])
      .map(mapIntegrationPointFromApi)
      .filter(isDefined),
    healthCheckUrl: apiResponse.healthCheckUrl,
    categories: apiResponse.categories ?? [],
    tags: apiResponse.tags ?? [],
    stats: mapAppStatsFromGeneratedApi(apiResponse.stats),
    installation: apiResponse.installation
      ? mapInstallationContextFromApi(apiResponse.installation)
      : undefined,
    updatedDate: apiResponse.updatedDate,
    createdDate: apiResponse.createdDate,
  };
}

/**
 * Maps AppVersion API response to frontend model
 */
export function mapAppVersionFromApi(api: AppVersionApiResponse): AppVersion {
  return {
    id: api.id,
    appDefinitionId: api.appDefinitionId,
    version: api.version,
    bumpType: api.bumpType,
    changelog: api.changelog,
    name: api.name,
    description: api.description,
    shortDescription: api.shortDescription,
    iconUrl: api.iconUrl,
    developerName: api.developerName,
    healthCheckUrl: api.healthCheckUrl,
    integrationPoints: api.integrationPoints
      .map(mapIntegrationPointFromApi)
      .filter(isDefined),
    categories: api.categories,
    tags: api.tags,
    status: api.status,
    state: api.state,
    visibility: api.visibility,
    feeModel: api.feeModel ? mapFeeModelFromApi(api.feeModel) : null,
    createdDate: api.createdDate,
    updatedDate: api.updatedDate,
  };
}

